func TestNoStoreMiddleware(t *testing.T) {
	sampleHandler := http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		w.WriteHeader(http.StatusOK)
	})

	handler := NoStoreMiddleware(sampleHandler)

	tests := []struct {
