 58 |   const $clear  = root.querySelector('#cmd-clear');
 59 | 
 60 |   /* ── state ── */
 61 |   let filtered=[], sel=-1;
 62 |   let mode='browse';           // 'browse' | 'awaiting'
 63 |   let pending=null;            // command awaiting free-text
 64 | 
 65 |   /* ── render ── */
 66 |   const render = () => {
 67 |     $list.innerHTML='';
 68 |     filtered.forEach((it,i)=>{
 69 |       const li=document.createElement('li');
 70 |       li.className='suggestion'+(i===sel?' active':'');
 71 |       li.innerHTML = it.kind==='command'
 72 |         ? it.path.map(p=>`<span class="crumb">${p}</span>`).join('')
 73 |         : `<span class="s-icon"><i class="fa-solid ${it.icon}"></i></span><span class="crumb">${it.label}</span>`;
 74 |       li.onclick=()=>run(it);
 75 |       $list.appendChild(li);
 76 |     });
 77 |   };
 78 | 
 79 |   const computeFiltered = q=>{
 80 |     if(!q) return [];
 81 |     const term=q.toLowerCase();
 82 |     return [...commandPool(),...buildElementPool()]
 83 |       .filter(i=>i.searchText.includes(term))
 84 |       .slice(0,cfg.maxResults);
 85 |   };
 86 | 
 87 |   /* ── helpers ── */
 88 |   const startInput = cmd=>{
 89 |     mode='awaiting';
 90 |     pending=cmd;
 91 |     $input.value='';
 92 |     $input.placeholder=cmd.path.at(-1)+'…';
 93 |     $input.focus();
 94 |     root.classList.add('awaiting');
 95 |     filtered=[]; sel=-1; render();
 96 |   };
 97 |   const quitInput=()=>{
 98 |     mode='browse'; pending=null;
 99 |     $input.placeholder='› Type a command…';
100 |     
101 |     reset();
102 |   };
103 | 
104 |   /* ── run ── */
105 |   function run(item){
106 |     if(!item) return;
107 |     if(item.kind==='command'){
108 |       if(item.needsInput){ startInput(item); return; }
109 |       item.action?.(controller);
110 |     }else{
111 |       controller.selectElement(item.id);
112 |       zoomToElement(controller,item.id);
113 |       controller.switchMode?.('navigate');
114 |     }
115 |     reset();
116 |   }
117 | 
118 |   const reset=()=>{
119 |     $input.value=''; sel=-1; filtered=[]; root.classList.add('empty'); render();
120 |   };
121 | 
122 |   /* ── zoom helper ── */
123 |   const zoomToElement=(ctrl,id)=>{
124 |     const el=ctrl.findElementById(id); if(!el) return;
125 |     const box=ctrl.canvas.getBoundingClientRect(), m=60;
126 |     const w=el.width*(el.scale||1)+m, h=el.height*(el.scale||1)+m;
127 |     ctrl.viewState.scale=Math.min(box.width/w,box.height/h,ctrl.MAX_SCALE);
128 |     ctrl.recenterOnElement(id); ctrl.updateCanvasTransform(); ctrl.saveLocalViewState?.();
129 |   };
130 | 
131 |   /* ── events ── */
132 |   $input.addEventListener('focus',()=>{
133 |     root.classList.add('focused'); window.scrollTo(0,0);
134 |   });
135 |   $input.addEventListener('input',e=>{
136 |     const q=e.target.value.trim();
137 |     root.classList.toggle('empty',q==='');
138 |     filtered=computeFiltered(q); sel=-1; render();
139 |   });
140 | 
141 |   $input.addEventListener('keydown',e=>{
142 |     if(e.key==='ArrowDown'&&filtered.length){ sel=(sel+1)%filtered.length; render(); e.preventDefault(); }
143 |     else if(e.key==='ArrowUp'&&filtered.length){ sel=(sel-1+filtered.length)%filtered.length; render(); e.preventDefault(); }
144 |     else if(e.key==='Enter'){
145 |       const val=$input.value.trim();
146 |       if(mode==='awaiting'){ pending?.action?.(controller,val); quitInput(); return; }
147 |       if(sel>=0) run(filtered[sel]);
148 |       else if(val){
149 |         const selId=controller.selectedElementId;
150 |         if(selId){
151 |           editElementWithPrompt(val,controller.findElementById(selId),controller).catch(console.error);
152 |           reset();
153 |         }else{
154 |           const r=controller.canvas.getBoundingClientRect();
155 |           const pt=controller.screenToCanvas(r.width/2,r.height/2);
156 |           controller.createNewElement(pt.x,pt.y,'markdown',val); reset();
157 |         }
158 |       }
159 |     }else if(e.key==='Escape'){
160 |       mode==='awaiting'?quitInput():reset();
161 |     }
162 |   });
163 | 
164 |   $clear.onclick=quitInput;
165 | 
166 |   window.addEventListener('keydown',e=>{
167 |     if((e.metaKey||e.ctrlKey)&&e.key.toLowerCase()==='k'){ e.preventDefault(); $input.focus(); $input.select(); }
168 |   });
169 | 
170 |   render();
171 | }
