 1 | /* ---------------------------------------------------------------------------
 2 |  * elementRegistry.js                (2025-05-04)
 3 |  * Simple plug-in registry for canvas element types.
 4 |  * ------------------------------------------------------------------------- */
 5 | 
 6 | export function createRegistry() {
 7 |   /** @type {Record<string,ElementView>} */
 8 |   const _views = {};
 9 | 
10 |   /** Register (or overwrite) a type */
11 |   function register(type, view) {
12 |     if (typeof type !== 'string' || !view || typeof view.mount !== 'function') {
13 |       throw new Error('register(type, view) – type string & view.mount() required');
14 |     }
15 |     _views[type] = view;
16 |   }
17 | 
18 |   /** Return the view object for a type, or undefined */
19 |   function viewFor(type) { return _views[type]; }
20 | 
21 |   /** Shallow copy of the currently known set */
22 |   function listTypes() { return Object.keys(_views); }
23 | 
24 |   return { register, viewFor, listTypes };
25 | }
26 | 
27 | /* single shared instance -------------------------------------------------- */
28 | export const elementRegistry = createRegistry();
29 | 
30 | /* make dynamic registration trivial for inline <script>                     */
31 | if (typeof window !== 'undefined') {
32 |   window.registerElementType = elementRegistry.register;
33 | }
34 | 
35 | /* -- Typing hint -----------------------------------------------------------
36 |  * An ElementView is just a plain object with three lifecycle hooks:
37 |  *   mount(el, controller)  -> HTMLElement   (called once)
38 |  *   update(el, dom, controller)             (called each change)
39 |  *   unmount?(dom)                           (called when removed)           */
