  1 | /**
  2 |  * CanvasController-aware helpers that *mutate model objects* but never touch
  3 |  * the DOM outside controller methods.  They are injected into gestureMachine
  4 |  * as XState actions.
  5 |  */
  6 | import { saveCanvas } from './storage.js';
  7 | import { generateContent } from './generation.js';
  8 | 
  9 | export function createGestureHelpers(controller) {
 10 | 
 11 |   const dpi = () => controller.viewState.scale || 1;     // “device-pixels” ⇄ canvas
 12 | 
 13 |   function commitElementMutation() {
 14 |     controller.requestRender();
 15 |     saveCanvas(controller.canvasState);
 16 |     controller._pushHistorySnapshot('Element change');
 17 |   }
 18 |   function persistViewState() {
 19 |     controller.saveLocalViewState();
 20 |     // controller._pushHistorySnapshot('View change');
 21 |   }
 22 | 
 23 |   function applyCanvasPan(ctx, ev) {
 24 |     if (!ctx.draft.start || !ctx.draft.view) return;
 25 |     const dx = ev.xy.x - ctx.draft.start.x;
 26 |     const dy = ev.xy.y - ctx.draft.start.y;
 27 |     controller.viewState.translateX = ctx.draft.view.translateX + dx;
 28 |     controller.viewState.translateY = ctx.draft.view.translateY + dy;
 29 |     controller.updateCanvasTransform();
 30 |   }
 31 | 
 32 |   function applyCanvasPinch(ctx, ev) {
 33 |     const pts = Object.values(ev.active || {});
 34 |     if (pts.length !== 2 || !ctx.draft.startDist) return;
 35 |     const [p1, p2] = pts;
 36 |     const newDist = Math.hypot(p2.x - p1.x, p2.y - p1.y);
