189 |     const a1 = Math.atan2(pts[1].y - pts[0].y, pts[1].x - pts[0].x);
190 |     const dAng = a1 - ctx.draft.startAngle;          // radians
191 | 
192 |     const { cx, cy } = ctx.draft.bboxCenter;
193 | 
194 |     controller.selectedElementIds.forEach(id => {
