199 |       const ox = start.offsetX * scale;
200 |       const oy = start.offsetY * scale;
201 |       const rotX = ox * Math.cos(dAng) - oy * Math.sin(dAng);
202 |       const rotY = ox * Math.sin(dAng) + oy * Math.cos(dAng);
203 | 
204 |       el.x = cx + rotX;
205 |       el.y = cy + rotY;
206 |       el.scale = start.scale * scale;    // ➋  propagate group-wide factor
