 24 | export function duplicateEl(c, id) {
 25 |   const el = c.findElementById(id);
 26 |   if (!el) return;
 27 |   const dup = { ...el, id: 'el-' + Date.now(), x: el.x + 20, y: el.y + 20 };
 28 |   c.canvasState.elements.push(dup);
 29 |   c.selectElement(dup.id);
 30 |   c.requestRender();
 31 |   saveCanvas(c.canvasState);
