 34 | export function deleteSelection(c) {
 35 |   if (!c.selectedElementIds.size) return;
 36 |   const keep = el => !c.selectedElementIds.has(el.id);
 37 |   /* drop elements */
 38 |   c.canvasState.elements = c.canvasState.elements.filter(keep);
 39 |   /* drop edges referencing deleted elements */
 40 |   c.canvasState.edges =
 41 |     c.canvasState.edges.filter(e => keep({ id: e.source }) && keep({ id: e.target }));
 42 |   c.clearSelection();
 43 |   c.requestRender();
 44 |   saveCanvas(c.canvasState);
 45 | }
