 47 | /* ─── clipboard helpers ──────────────────────────────────────────────────── */
 48 | 
 49 | export function copySelection(c) {
 50 |   if (!c.selectedElementIds.size) return;
 51 |   const els = c.canvasState.elements
 52 |     .filter(el => c.selectedElementIds.has(el.id))
 53 |     .map(el => ({ ...el }));                               // deepish clone
 54 |   try { navigator.clipboard?.writeText(JSON.stringify(els)); } catch { }
 55 |   _clip.elements = els;
 56 | }
 57 | 
 58 | export function clipboardHasContent() {
 59 |   return Array.isArray(_clip.elements) && _clip.elements.length > 0;
 60 | }
 61 | 
 62 | export async function pasteClipboard(c) {
 63 |   if (!clipboardHasContent()) return;
 64 |   /* offset new items a bit */
 65 |   const now = Date.now();
 66 |   const pastedEls = _clip.elements.map((el, i) => ({
 67 |     ...el,
 68 |     id: 'el-' + (now + i),
 69 |     x: el.x + 30,
 70 |     y: el.y + 30
 71 |   }));
 72 |   c.canvasState.elements.push(...pastedEls);
 73 |   c.selectedElementIds = new Set(pastedEls.map(e => e.id));
 74 |   c.requestRender();
 75 |   saveCanvas(c.canvasState);
 76 | }
