 80 | export async function generateNew(c) {
 81 |   if (c.selectedElementIds.size !== 1) return;
 82 |   const id = [...c.selectedElementIds][0];
 83 |   const el = c.findElementById(id);
 84 |   if (!el || el.type === 'img') return;
