144 | /* ─── viewport helpers ───────────────────────────────────────────────────── */
145 | 
146 | export function zoom(c, factor) {
147 |   c.viewState.scale = Math.min(
148 |     Math.max(c.viewState.scale * factor, c.MIN_SCALE), c.MAX_SCALE);
149 |   c.updateCanvasTransform();
150 |   c.saveLocalViewState?.();
151 | }
152 | 
153 | export function zoomToFit(c) {
154 |   /* fit all elements’ bounding box into the visible canvas */
155 |   if (!c.canvasState.elements.length) return;
156 |   const xs = [], ys = [], xe = [], ye = [];
157 |   c.canvasState.elements.forEach(el => {
158 |     const s = el.scale || 1;
159 |     xs.push(el.x - el.width * s / 2);
160 |     ys.push(el.y - el.height * s / 2);
161 |     xe.push(el.x + el.width * s / 2);
162 |     ye.push(el.y + el.height * s / 2);
163 |   });
164 |   const bb = {
165 |     x1: Math.min(...xs), y1: Math.min(...ys),
166 |     x2: Math.max(...xe), y2: Math.max(...ye)
167 |   };
168 |   const W = c.canvas.clientWidth, H = c.canvas.clientHeight;
169 |   const scaleX = W / (bb.x2 - bb.x1), scaleY = H / (bb.y2 - bb.y1);
170 |   c.viewState.scale = Math.min(scaleX, scaleY) * 0.85;          // 15 % margin
171 |   c.viewState.translateX = -bb.x1 * c.viewState.scale + (W - (bb.x2 - bb.x1) * c.viewState.scale) / 2;
172 |   c.viewState.translateY = -bb.y1 * c.viewState.scale + (H - (bb.y2 - bb.y1) * c.viewState.scale) / 2;
173 |   c.updateCanvasTransform();
174 |   c.saveLocalViewState?.();
175 | }
