186 |   const data = JSON.stringify(c.canvasState, null, 2);
187 |   const blob = new Blob([data], { type: 'application/json' });
188 |   const url = URL.createObjectURL(blob);
189 |   const a = document.createElement('a');
190 |   a.href = url; a.download = `${c.canvasState.canvasId}.json`;
191 |   a.click();
192 |   URL.revokeObjectURL(url);
