105 | function hydrateUiFor(el) {
106 |   /* editors (lazy) */
107 |   if (!cmContent) {
108 |     cmContent = CodeMirror($contentEditorHost, {
109 |       value: '', mode: getMode(el.type), lineNumbers: true,
110 |       theme: 'default', lineWrapping: true
111 |     });
112 |   } else {
113 |     cmContent.setOption('mode', getMode(el.type));
114 |   }
115 |   if (!cmSrc) {
116 |     cmSrc = CodeMirror($srcEditorHost, {
117 |       value: '', mode: 'text', lineNumbers: true,
118 |       theme: 'default', lineWrapping: true
119 |     });
120 |   }
121 | 
122 |   currentEl = el;
123 |   currentVerIdx = (el.versions ?? []).length; // point to “current”
124 |   activeTab = (el.type === 'img' && el.src) ? 'src' : 'content';
125 |   switchTab(activeTab, /*silent=*/true);
126 | 
127 |   loadVersion(currentVerIdx);
128 |   clearError();
129 | 
130 |   $root.style.display = "block";
131 | }
