133 | function loadVersion(idx) {
134 |   const vCount = (currentEl.versions ?? []).length;
135 |   currentVerIdx = idx = Math.max(0, Math.min(idx, vCount));
136 | 
137 |   if (idx < vCount) {
138 |     cmContent.setValue(currentEl.versions[idx].content);
139 |   } else {
140 |     cmContent.setValue(currentEl.content ?? '');
141 |   }
142 |   cmSrc.setValue(currentEl.src ?? '');
143 | 
144 |   $info.textContent = `Version ${idx + 1} of ${vCount + 1}`;
145 | }
