154 |   $tabSrc.classList.toggle('active', tab === 'src');
155 |   $contentEditorHost.style.display = tab === 'content' ? 'block' : 'none';
156 |   $srcEditorHost.style.display = tab === 'src' ? 'block' : 'none';
157 |   if (!silent) getActiveCM().refresh();
