166 |     const newContent = cmContent.getValue();
167 |     if (currentEl.content !== newContent) {
168 |       currentEl.versions = currentEl.versions ?? [];
169 |       currentEl.versions.push({ content: currentEl.content, timestamp: Date.now() });
170 |       currentEl.content = newContent;
171 |       if (currentEl.type !== 'img') currentEl.src = undefined;
172 |     }
173 |   } else {            // src tab
174 |     currentEl.src = cmSrc.getValue();
