  1 | // ----------------------------------------------------------------------------
  2 | // Thin DOM ⇆ FSM bridge.
  3 | // Converts native pointer / wheel events into *pure* FSM events.
  4 | // ----------------------------------------------------------------------------
  5 | export function installPointerAdapter(
  6 |   rootEl,
  7 |   service,
  8 |   getViewState,
  9 |   selected = () => new Set()
 10 | ) {
 11 | 
 12 |   const active = new Map(); // pointerId → {x,y}
 13 |   const capturedTargets = new Map(); // pointerId → element that we called setPointerCapture on
 14 | 
 15 |   let lastTap = { t: 0, x: 0, y: 0 };
 16 |   const TAP_MS = 300;
 17 |   const TAP_DIST = 10;
 18 | 
 19 |   const classifyHandle = (node) => {
 20 |     if (!node) return null;
 21 |     if(node.id === 'group-box') return null;         // click on the bbox itself
 22 | if(node.closest('#group-box')){
 23 |   if(node.classList.contains('resize-handle')) return 'resize';
 24 |   if(node.classList.contains('rotate-handle')) return 'rotate';
 25 |   if(node.classList.contains('scale-handle'))  return 'scale';
 26 | }
 27 |     if (node.classList.contains('resize-handle')) return 'resize';
 28 |     if (node.classList.contains('scale-handle')) return 'scale';
 29 |     if (node.classList.contains('rotate-handle')) return 'rotate';
 30 |     if (node.classList.contains('reorder-handle')) return 'reorder';
 31 |     if (node.classList.contains('edge-handle')) return 'edge';
 32 |     if (node.classList.contains('create-handle')) return 'createNode';
 33 |     if (node.classList.contains('type-handle')) return 'type';
 34 |     
 35 |     return null;
 36 |   };
 37 | 
 38 |   const send = (type, ev, extra = {}) => {
 39 |     const xy = { x: ev.clientX, y: ev.clientY };
 40 |     const elementNode = ev.target.closest('.canvas-element');
 41 |     const handleNode = ev.target.closest('.element-handle');
 42 |     const edgeLabelNode = ev.target.closest('text[data-id]');
 43 | 
 44 |     const payload = {
 45 |       type,
 46 |       xy,
 47 |       active: Object.fromEntries(active),
 48 |       hitElement: !!elementNode,
 49 |       elementId: elementNode ? elementNode.dataset.elId : null,
 50 |       handle: classifyHandle(handleNode),
 51 |       edgeLabel: !!edgeLabelNode,
 52 |       edgeId: edgeLabelNode ? edgeLabelNode.dataset.id : null,
 53 |       selected: selected(),
 54 |       view: getViewState(),
 55 |       ev, // raw DOM event
 56 |       ...extra
 57 |     }
 58 |     if (payload.type !== 'POINTER_MOVE') console.log("[FSM] Pointer adapter event send:", active.size, ev.pointerId, payload)
 59 |     service.send(payload);
 60 |   };
 61 | 
 62 |   const onPointerDown = (ev) => {
 63 |     ev.preventDefault();
 64 |     active.set(ev.pointerId, { x: ev.clientX, y: ev.clientY });
 65 |     const handleNode = ev.target.closest('.element-handle');
 66 |     const edgeLabelNode = ev.target.closest('text[data-id]');
 67 |     const elementNode = ev.target.closest('.canvas-element');
 68 |     const captureNode = handleNode
 69 |       || edgeLabelNode
 70 |       || elementNode
 71 |       || rootEl;
 72 | 
 73 |     // 3) capture on that node and store it
 74 |     captureNode.setPointerCapture(ev.pointerId);
 75 |     capturedTargets.set(ev.pointerId, captureNode);
 76 | 
 77 |     ev.target.setPointerCapture(ev.pointerId);
 78 |     send('POINTER_DOWN', ev);
 79 |     startLongPress(ev);
 80 | 
 81 |   };
 82 | 
 83 |   /* — LONG-PRESS helper — */
 84 |   let lpTimer = null;
 85 |   const LP_DELAY = 600;                     // ms
 86 |   function startLongPress(ev) {
 87 |     lpTimer = setTimeout(() => {
 88 |       send('LONG_PRESS', ev);                // new pure FSM event
 89 |       lpTimer = null;
 90 |     }, LP_DELAY);
 91 |   }
 92 |   function cancelLongPress() { clearTimeout(lpTimer); lpTimer = null; }
 93 | 
 94 |   const onPointerMove = (ev) => {
 95 |     if (!active.has(ev.pointerId)) return;
 96 |     active.set(ev.pointerId, { x: ev.clientX, y: ev.clientY });
 97 |     cancelLongPress();
 98 |     send('POINTER_MOVE', ev);
 99 |   };
100 |   const finishPointer = (ev) => {
101 |     ev.preventDefault();
102 |     cancelLongPress();
103 |     active.delete(ev.pointerId);
104 |     // release capture on whichever node we grabbed
105 |     const capNode = capturedTargets.get(ev.pointerId) || rootEl;
106 |     capNode.releasePointerCapture(ev.pointerId);
107 |     capturedTargets.delete(ev.pointerId);
108 | 
109 |     send('POINTER_UP', ev);
110 | 
111 |     /*  tap / double-tap detection  */
112 |     if (ev.button === 0) {
113 |       const dt = ev.timeStamp - lastTap.t;
114 |       const dist = Math.hypot(ev.clientX - lastTap.x, ev.clientY - lastTap.y);
115 |       if (dt < TAP_MS && dist < TAP_DIST) {
116 |         send('DOUBLE_TAP', ev);
117 |         lastTap.t = 0; // reset
118 |       } else {
119 |         lastTap = { t: ev.timeStamp, x: ev.clientX, y: ev.clientY };
120 |       }
121 |     }
122 |   };
123 |   const onWheel = (ev) => send('WHEEL', ev, { deltaY: ev.deltaY });
124 |   const onKeyup = (ev) => {
125 |     console.log("[PointerAdapter] keyup", ev)
126 |     send('KEYUP', ev, { key: ev.key });
127 |   }
128 |   const onKeydown = (ev) => {
129 |     console.log("[PointerAdapter] keydown", ev)
130 |     if ((ev.metaKey || ev.ctrlKey) && ev.key === 'z') {
131 |       ev.preventDefault();
132 |       if (ev.shiftKey) service.state.context.controller.redo();
133 |       else service.state.context.controller.undo();
134 |       return;           // don’t forward to FSM
135 |     }
136 | 
137 |     send('KEYDOWN', ev, { key: ev.key });
138 |   }
139 | 
140 | 
141 |   /* listeners */
142 |   rootEl.addEventListener('pointerdown', onPointerDown, { passive: false });
143 |   rootEl.addEventListener('pointermove', onPointerMove, { passive: true });
144 |   rootEl.addEventListener('pointerup', finishPointer, { passive: false });
145 |   rootEl.addEventListener('pointercancel', finishPointer, { passive: true });
146 |   rootEl.addEventListener('wheel', onWheel, { passive: true });
147 |   window.addEventListener('keydown', onKeydown, { passive: true });
148 |   window.addEventListener('keyup', onKeyup, { passive: true });
149 | 
150 |   /* teardown helper */
151 |   return () => {
152 |     rootEl.removeEventListener('pointerdown', onPointerDown);
153 |     rootEl.removeEventListener('pointermove', onPointerMove);
154 |     rootEl.removeEventListener('pointerup', finishPointer);
155 |     rootEl.removeEventListener('pointercancel', finishPointer);
156 |     rootEl.removeEventListener('wheel', onWheel);
157 |     window.removeEventListener('keydown', onKeydown);
158 |     window.removeEventListener('keyup', onKeyup);
159 |   };
160 | }
161 | 


