 303 |     getGroupBBox() {
 304 |         if (this.selectedElementIds.size === 0) return null;
 305 |         const els = [...this.selectedElementIds].map(id => this.findElementById(id));
 306 |         const xs = els.map(e => e.x - (e.width * (e.scale || 1)) / 2);
 307 |         const ys = els.map(e => e.y - (e.height * (e.scale || 1)) / 2);
 308 |         const xe = els.map(e => e.x + (e.width * (e.scale || 1)) / 2);
 309 |         const ye = els.map(e => e.y + (e.height * (e.scale || 1)) / 2);
 310 |         return {
 311 |             x1: Math.min(...xs), y1: Math.min(...ys),
 312 |             x2: Math.max(...xe), y2: Math.max(...ye),
 313 |             cx: (Math.min(...xs) + Math.max(...xe)) / 2,
 314 |             cy: (Math.min(...ys) + Math.max(...ye)) / 2
 315 |         };
 316 |     }
