 373 |     updateCanvasTransform() {
 374 |         if (this.canvas.controller !== this) return;
 375 | 
 376 |         this.container.style.transform = `translate(${this.viewState.translateX}px, ${this.viewState.translateY}px) scale(${this.viewState.scale})`;
 377 |         this.container.style.setProperty('--translateX', this.viewState.translateX);
 378 |         this.container.style.setProperty('--translateY', this.viewState.translateY);
 379 |         this.container.style.setProperty('--zoom', this.viewState.scale);
 380 | 
 381 |         // Get the canvas (visible) size
 382 |         const canvasRect = this.canvas.getBoundingClientRect();
 383 |         const W = canvasRect.width;
 384 |         const H = canvasRect.height;
 385 | 
 386 |         // Compute the visible region in canvas coordinates:
 387 |         const visibleX = -this.viewState.translateX / this.viewState.scale;
 388 |         const visibleY = -this.viewState.translateY / this.viewState.scale;
 389 |         const visibleWidth = W / this.viewState.scale;
 390 |         const visibleHeight = H / this.viewState.scale;
 391 | 
 392 |         // Set the viewBox attribute on the SVG layer so that its coordinate system
 393 |         // matches the visible region.
 394 |         this.edgesLayer.setAttribute("viewBox", `${visibleX} ${visibleY} ${visibleWidth} ${visibleHeight}`);
 395 |         // console.log("[DEBUG] SVG viewBox updated to:", visibleX, visibleY, visibleWidth, visibleHeight);
 396 | 
 397 |         this.updateGroupBox()
