 407 |         // Compute the center of the element in canvas coordinates
 408 |         const scale = this.viewState.scale || 1;
 409 |         const elCenterX = el.x;
 410 |         const elCenterY = el.y;
 411 | 
 412 |         // Get canvas size in pixels
 413 |         const canvasRect = this.canvas.getBoundingClientRect();
 414 |         const canvasCenterX = canvasRect.width / 2;
 415 |         const canvasCenterY = canvasRect.height / 2;
