 520 |     updateEdgePosition(edge, line) {
 521 |         if (!line) return;
 522 |         const sourceEl = this.findElementById(edge.source);
 523 |         const targetEl = this.findElementById(edge.target);
 524 |         const sourceEdge = sourceEl ? null : this.findEdgeElementById(edge.source);
 525 |         const targetEdge = targetEl ? null : this.findEdgeElementById(edge.target);
 526 | 
 527 |         let sourcePoint, targetPoint;
 528 |         if ((sourceEl || sourceEdge) && (targetEl || targetEdge)) {
 529 |             sourcePoint = this.computeIntersection(sourceEl || {
 530 |                 x: parseFloat(this.edgeLabelNodesMap[edge.source].getAttribute("x")),
 531 |                 y: parseFloat(this.edgeLabelNodesMap[edge.source].getAttribute("y"))
 532 |             }, targetEl || {
 533 |                 x: parseFloat(this.edgeLabelNodesMap[edge.target].getAttribute("x")),
 534 |                 y: parseFloat(this.edgeLabelNodesMap[edge.target].getAttribute("y"))
 535 |             });
 536 |             targetPoint = this.computeIntersection(targetEl || {
 537 |                 x: parseFloat(this.edgeLabelNodesMap[edge.target].getAttribute("x")),
 538 |                 y: parseFloat(this.edgeLabelNodesMap[edge.target].getAttribute("y"))
 539 |             }, sourceEl || {
 540 |                 x: parseFloat(this.edgeLabelNodesMap[edge.source].getAttribute("x")),
 541 |                 y: parseFloat(this.edgeLabelNodesMap[edge.source].getAttribute("y"))
 542 |             });
 543 |         }
 544 | 
 545 |         if (sourcePoint && targetPoint) {
 546 |             line.setAttribute("x1", sourcePoint.x);
 547 |             line.setAttribute("y1", sourcePoint.y);
 548 |             line.setAttribute("x2", targetPoint.x);
 549 |             line.setAttribute("y2", targetPoint.y);
 550 |             line.setAttribute("stroke-dasharray", edge.data?.meta ? "5,5" : edge.style?.dash || "");
 551 | 
 552 |             // Handle edge label:
 553 |             // Use a default label if none is present.
 554 |             const labelText = edge.label ? edge.label : "Edge";
 555 |             if (!this.edgeLabelNodesMap) this.edgeLabelNodesMap = {};
 556 |             let textEl = this.edgeLabelNodesMap[edge.id];
 557 |             if (!textEl) {
 558 |                 textEl = document.createElementNS("http://www.w3.org/2000/svg", "text");
 559 |                 textEl.setAttribute("text-anchor", "middle");
 560 |                 textEl.setAttribute("data-id", edge.id);
 561 |                 textEl.setAttribute("alignment-baseline", "middle");
 562 |                 textEl.setAttribute("fill", "#000");
 563 |                 textEl.style.fontSize = "12px";
 564 |                 if (this.selectedElementId === edge.id) textEl.style.fill = "red";
 565 |                 this.edgeLabelNodesMap[edge.id] = textEl;
 566 |                 this.edgesLayer.appendChild(textEl);
 567 |             }
 568 |             // Calculate midpoint of the line.
 569 |             const midX = (sourcePoint.x + targetPoint.x) / 2;
 570 |             const midY = (sourcePoint.y + targetPoint.y) / 2;
 571 |             textEl.setAttribute("x", midX);
 572 |             textEl.setAttribute("y", midY);
 573 |             textEl.textContent = labelText;
 574 | 
 575 |         } else {
 576 |             this.canvasState.edges = this.canvasState.edges.filter(ed => ed.id !== edge.id);
 577 |             line.remove();
 578 |         }
 579 |     }
