 644 |     async executeScriptElements(el, node) {
 645 |         // defer execution
 646 |         await new Promise(r => requestAnimationFrame(r));
 647 |   const scriptElements = Array.from(node.querySelectorAll('script'));
 648 | 
 649 |   const loadScript = (script) => {
 650 |     return new Promise((resolve, reject) => {
 651 |       script.onload  = resolve;
 652 |       script.onerror = () => {
 653 |         this._showElementError(node.closest('.canvas-element'),
 654 |           `Failed to load\n${script.getAttribute('src')}`);
 655 |         reject(new Error(`Failed to load script: ${script.getAttribute('src')}`));
 656 |       };
 657 |       document.head.appendChild(script);
 658 |     });
 659 |   };
 660 | 
 661 |   for (const scriptElement of scriptElements) {
 662 |     if (scriptElement.type !== 'module' &&
 663 |         !scriptElement.getAttribute('src') &&
 664 |         scriptElement.textContent.trim()) {
 665 | 
 666 |       try {
 667 |         const fn = new Function('element', 'controller', 'node',
 668 |                                 scriptElement.textContent);
 669 |         fn(el, this, node);
 670 |       } catch (err) {
 671 |         console.warn('Inline script error', err);
 672 |         this._showElementError(node.closest('.canvas-element'), err.message);
 673 |       }
 674 | 
 675 |     } else {
 676 |       await loadScript(scriptElement);
 677 |     }
 678 |   }
 679 | }
