1073 |     computeIntersection(el, otherEl) {
1074 |         // 1) Center and scale as before
1075 |         const cx = el.x;
1076 |         const cy = el.y;
1077 |         const scaleFactor = el.scale || 1;
1078 |         const w = (el.width || 10) * scaleFactor;
1079 |         const h = (el.height || 10) * scaleFactor;
1080 |         const halfW = w / 2;
1081 |         const halfH = h / 2;
1082 |     
1083 |         // 2) Vector from el center to otherEl
1084 |         let dx = otherEl.x - cx;
1085 |         let dy = otherEl.y - cy;
1086 |     
1087 |         // If same point, return center
1088 |         if (dx === 0 && dy === 0) {
1089 |             return { x: cx, y: cy };
1090 |         }
1091 |     
1092 |         // 3) Un-rotate the direction vector into the rectangle's local axes
1093 |         const theta = ((el.rotation || 0) * Math.PI) / 180;
1094 |         const cosθ = Math.cos(-theta);
1095 |         const sinθ = Math.sin(-theta);
1096 |         const localDX = dx * cosθ - dy * sinθ;
1097 |         const localDY = dx * sinθ + dy * cosθ;
1098 |     
1099 |         // 4) Compute intersection on an axis-aligned box in local space
1100 |         const scaleX = localDX !== 0 ? halfW / Math.abs(localDX) : Infinity;
1101 |         const scaleY = localDY !== 0 ? halfH / Math.abs(localDY) : Infinity;
1102 |         const scale  = Math.min(scaleX, scaleY);
1103 |     
1104 |         const localIX = localDX * scale;
1105 |         const localIY = localDY * scale;
1106 |     
1107 |         // 5) Rotate the intersection point back into world axes
1108 |         const cosθf = Math.cos(theta);
1109 |         const sinθf = Math.sin(theta);
1110 |         const worldIX = localIX * cosθf - localIY * sinθf;
1111 |         const worldIY = localIX * sinθf + localIY * cosθf;
1112 |     
1113 |         // 6) Translate back to world coordinates
1114 |         return {
1115 |             x: cx + worldIX,
1116 |             y: cy + worldIY
1117 |         };
1118 |     }
