    let guessedAnimal2 = this.extractImageName(guessedAnimalImages[1]).toLowerCase();


    if ((animal1 + '.jpeg' === guessedAnimal1 && animal2 + '.jpeg' === guessedAnimal2) || (animal1 + '.jpeg' === guessedAnimal2 && animal2 + '.jpeg' === guessedAnimal1)) {
